SELECT * FROM ( SELECT ROW_NUMBER() OVER (ORDER BY A2.SBSCRB_DE DESC) AS RNUM , COALESCE(A2.ESNTL_ID, '') AS ESNTL_ID , COALESCE(A2.USER_ID, '') AS USER_ID , COALESCE(DECRYPT(A2.USER_NM), '') AS USER_NM , COALESCE(DECRYPT(A2.EMAIL_ADRES), '') AS EMAIL_ADRES , COALESCE(FN_MASK_PHONE(DECRYPT(A2.USR_TELNO), 'N'), '') AS USR_TELNO , COALESCE(FN_MASK_PHONE(DECRYPT(A2.MBTLNUM), 'N'), '') AS MBTLNUM , COALESCE(DATE_FORMAT(STR_TO_DATE(A2.BRTHDY, '%Y%m%d'), '%Y-%m-%d'), '') AS BRTHDY , COALESCE(A2.SEXDSTN_CODE, 'M') AS SEXDSTN_CODE , COALESCE(DECRYPT(A2.ZIP), '') AS ZIP , COALESCE(DECRYPT(A2.ADRES_LOT), '') AS ADRES_LOT , COALESCE(DECRYPT(A2.ADRES), '') AS ADRES , COALESCE(DECRYPT(A2.DETAIL_ADRES), '') AS DETAIL_ADRES , COALESCE(FN_MASK_PHONE(DECRYPT(A2.OFFM_TELNO), 'N'), '') AS OFFM_TELNO , COALESCE(DECRYPT(A2.FXNUM), '') AS FXNUM , COALESCE(A2.MBER_STTUS, '') AS MBER_STTUS , CASE A2.MBER_STTUS WHEN 'A' THEN '대기' WHEN 'P' THEN '사용' WHEN 'D' THEN '탈퇴' ELSE A2.MBER_STTUS END AS MBER_STTUS_NM , COALESCE(DATE_FORMAT(A2.SBSCRB_DE, '%Y-%m-%d'), '') AS SBSCRB_DE , COALESCE(DATE_FORMAT(A2.SECSN_DE, '%Y-%m-%d'), '') AS SECSN_DE , COALESCE(IF(A2.LOCK_AT = 'Y', '잠금', '해제'), '해제') AS LOCK_AT , COALESCE(A2.USER_SE, '') AS USER_SE , COALESCE(DATE_FORMAT(A2.CHG_LAST_DT, '%Y-%m-%d %H:%i:%s'), '') AS CHG_LAST_DT , COALESCE(DECRYPT(A2.IHIDNUM), A2.IHIDNUM, '') AS IHIDNUM , COALESCE(A2.SCHOOL_ID, '') AS SCHOOL_ID , COALESCE(A2.SCHOOL_GB, '') AS SCHOOL_GB , COALESCE(A2.SCHOOL_NM, '') AS SCHOOL_NM , COALESCE(A2.SCHOOL_LVL, 0) AS SCHOOL_LVL , COALESCE(A2.SCHOOL_NO, 0) AS SCHOOL_NO , COALESCE(A2.PAY_BANK_CODE, '') AS PAY_BANK_CODE , COALESCE((SELECT CODE_NM FROM LETTCCMMNDETAILCODE WHERE CODE_ID = 'ARM002' AND CODE = A2.PAY_BANK_CODE), '') AS PAY_BANK_CODE_NM , COALESCE(DECRYPT(A2.PAY_BANK), '') AS PAY_BANK , COALESCE(DECRYPT(A2.HOLDER_NM), '') AS HOLDER_NM , COALESCE(A2.GROUP_ID, '') AS GROUP_ID , COALESCE(A2.ORGNZT_ID, '') AS ORGNZT_ID , COALESCE(A2.INDUTY_CODE, '') AS INDUTY_CODE , COALESCE(A2.BIZRNO, '') AS BIZRNO , COALESCE(A2.ENTRPRS_SE_CODE, '') AS ENTRPRS_SE_CODE , COALESCE(A2.CXFC, '') AS CXFC , COALESCE(A2.PSTINST_CODE, '') AS PSTINST_CODE , COALESCE(A2.OFCPS_NM, '') AS OFCPS_NM , COALESCE(A2.EMPL_NO, '') AS EMPL_NO , COALESCE(A2.APPLCNT_NM, '') AS APPLCNT_NM , COALESCE(A2.CRTFC_DN_VALUE, '') AS CRTFC_DN_VALUE , COALESCE(A2.CRTFC_CN_VALUE, '') AS CRTFC_CN_VALUE , COALESCE(A2.TOKEN_ID, '') AS TOKEN_ID , A2.LOCK_CNT AS LOCK_CNT , COALESCE(DATE_FORMAT(A2.LOCK_LAST_PNTTM, '%Y-%m-%d %H:%i:%s'), '') AS LOCK_LAST_PNTTM , COALESCE(DATE_FORMAT(A2.CHG_PWD_LAST_PNTTM, '%Y-%m-%d %H:%i:%s'), '') AS CHG_PWD_LAST_PNTTM , COALESCE(A2.TERMS1_YN, 'N') AS TERMS1_YN , COALESCE(A2.TERMS2_YN, 'N') AS TERMS2_YN , COALESCE(A2.TERMS3_YN, 'N') AS TERMS3_YN , COALESCE(A2.TERMS4_YN, 'N') AS TERMS4_YN , COALESCE(A2.NOTICE_YN, 'N') AS NOTICE_YN , COALESCE(A2.EVENT_NOTI_YN, 'N') AS EVENT_NOTI_YN , COALESCE(A2.MAIL_NOTI_YN, 'N') AS MAIL_NOTI_YN , COALESCE(A2.SMS_NOTI_YN, 'N') AS SMS_NOTI_YN , COALESCE(A2.CERT_YN, 'N') AS CERT_YN , COALESCE(DATE_FORMAT(A2.CERT_DATE, '%Y-%m-%d %H:%i:%s'), '') AS CERT_DATE , COALESCE(A2.PROFILE, '') AS PROFILE , COALESCE(A2.PROFILE_GB, '') AS PROFILE_GB , COALESCE(A2.TEST_YN, 'N') AS TEST_YN , COALESCE(A2.SESSION_KEY, '') AS SESSION_KEY , COALESCE(DATE_FORMAT(A2.SESSION_LIMIT, '%Y-%m-%d %H:%i:%s'), '') AS SESSION_LIMIT , COALESCE(DATE_FORMAT(A2.APPROVE_DE, '%Y-%m-%d'), '') AS APPROVE_DE , COALESCE(A2.USER_PIC, '') AS USER_PIC , COALESCE(A2.CITIZEN_YN, 'N') AS CITIZEN_YN , COALESCE(A2.SINGLE_YN, 'N') AS SINGLE_YN , COALESCE(A2.MINOR_YN, 'N') AS MINOR_YN , COALESCE(A2.BASIC_YN, 'N') AS BASIC_YN , COALESCE(A2.POOR_YN, 'N') AS POOR_YN , CASE WHEN A2.BASIC_YN = 'Y' AND A2.POOR_YN = 'Y' THEN '기초생활수급자, 차상위계층' WHEN A2.BASIC_YN = 'Y' THEN '기초생활수급자' WHEN A2.POOR_YN = 'Y' THEN '차상위계층' ELSE '' END AS LOW_INCOME_NM , COALESCE(A2.FARM_YN, 'N') AS FARM_YN , COALESCE(A2.ATTA_FILE, '') AS ATTA_FILE , COALESCE(A2.SUBJECT_DESC, '') AS SUBJECT_DESC , COALESCE(A2.PROFILE_DESC, '') AS PROFILE_DESC , COALESCE(A2.BIZNO_FILE, '') AS BIZNO_FILE , COALESCE(A2.RELATION_GB, 'M') AS RELATION_GB , CASE A2.RELATION_GB WHEN 'F' THEN '부' WHEN 'M' THEN '모' WHEN 'E' THEN '기타' ELSE '' END AS RELATION_GB_NM , COALESCE(A2.FARM_DESC, '') AS FARM_DESC FROM ARMUSER A2 WHERE 1=1
AND A2.USER_SE = #{userSe}
AND DECRYPT(A2.USER_NM) LIKE CONCAT('%', #{searchKeyword}, '%')
AND A2.USER_ID LIKE CONCAT('%', #{searchKeyword}, '%')
AND DECRYPT(A2.MBTLNUM) LIKE CONCAT('%', #{searchKeyword}, '%')
AND A2.MBER_STTUS = #{mberSttus}
) A1 LIMIT #{lengthPage} OFFSET #{startIndex}

SELECT * FROM ( SELECT ROW_NUMBER() OVER (ORDER BY A2.SBSCRB_DE DESC) AS RNUM , COALESCE(A2.ESNTL_ID, '') AS ESNTL_ID , COALESCE(A2.USER_ID, '') AS USER_ID , COALESCE(DECRYPT(A2.USER_NM), '') AS USER_NM , COALESCE(DECRYPT(A2.EMAIL_ADRES), '') AS EMAIL_ADRES , COALESCE(FN_MASK_PHONE(DECRYPT(A2.USR_TELNO), 'N'), '') AS USR_TELNO , COALESCE(FN_MASK_PHONE(DECRYPT(A2.MBTLNUM), 'N'), '') AS MBTLNUM , COALESCE(DATE_FORMAT(STR_TO_DATE(A2.BRTHDY, '%Y%m%d'), '%Y-%m-%d'), '') AS BRTHDY , COALESCE(A2.SEXDSTN_CODE, 'M') AS SEXDSTN_CODE , COALESCE(DECRYPT(A2.ZIP), '') AS ZIP , COALESCE(DECRYPT(A2.ADRES_LOT), '') AS ADRES_LOT , COALESCE(DECRYPT(A2.ADRES), '') AS ADRES , COALESCE(DECRYPT(A2.DETAIL_ADRES), '') AS DETAIL_ADRES , COALESCE(FN_MASK_PHONE(DECRYPT(A2.OFFM_TELNO), 'N'), '') AS OFFM_TELNO , COALESCE(DECRYPT(A2.FXNUM), '') AS FXNUM , COALESCE(A2.MBER_STTUS, '') AS MBER_STTUS , CASE A2.MBER_STTUS WHEN 'A' THEN '대기' WHEN 'P' THEN '사용' WHEN 'D' THEN '탈퇴' ELSE A2.MBER_STTUS END AS MBER_STTUS_NM , COALESCE(DATE_FORMAT(A2.SBSCRB_DE, '%Y-%m-%d'), '') AS SBSCRB_DE , COALESCE(DATE_FORMAT(A2.SECSN_DE, '%Y-%m-%d'), '') AS SECSN_DE , COALESCE(IF(A2.LOCK_AT = 'Y', '잠금', '해제'), '해제') AS LOCK_AT , COALESCE(A2.USER_SE, '') AS USER_SE , COALESCE(DATE_FORMAT(A2.CHG_LAST_DT, '%Y-%m-%d %H:%i:%s'), '') AS CHG_LAST_DT , COALESCE(DECRYPT(A2.IHIDNUM), A2.IHIDNUM, '') AS IHIDNUM , COALESCE(A2.SCHOOL_ID, '') AS SCHOOL_ID , COALESCE(A2.SCHOOL_GB, '') AS SCHOOL_GB , COALESCE(A2.SCHOOL_NM, '') AS SCHOOL_NM , COALESCE(A2.SCHOOL_LVL, 0) AS SCHOOL_LVL , COALESCE(A2.SCHOOL_NO, 0) AS SCHOOL_NO , COALESCE(A2.PAY_BANK_CODE, '') AS PAY_BANK_CODE , COALESCE((SELECT CODE_NM FROM LETTCCMMNDETAILCODE WHERE CODE_ID = 'ARM002' AND CODE = A2.PAY_BANK_CODE), '') AS PAY_BANK_CODE_NM , COALESCE(DECRYPT(A2.PAY_BANK), '') AS PAY_BANK , COALESCE(DECRYPT(A2.HOLDER_NM), '') AS HOLDER_NM , COALESCE(A2.GROUP_ID, '') AS GROUP_ID , COALESCE(A2.ORGNZT_ID, '') AS ORGNZT_ID , COALESCE(A2.INDUTY_CODE, '') AS INDUTY_CODE , COALESCE(A2.BIZRNO, '') AS BIZRNO , COALESCE(A2.ENTRPRS_SE_CODE, '') AS ENTRPRS_SE_CODE , COALESCE(A2.CXFC, '') AS CXFC , COALESCE(A2.PSTINST_CODE, '') AS PSTINST_CODE , COALESCE(A2.OFCPS_NM, '') AS OFCPS_NM , COALESCE(A2.EMPL_NO, '') AS EMPL_NO , COALESCE(A2.APPLCNT_NM, '') AS APPLCNT_NM , COALESCE(A2.CRTFC_DN_VALUE, '') AS CRTFC_DN_VALUE , COALESCE(A2.CRTFC_CN_VALUE, '') AS CRTFC_CN_VALUE , COALESCE(A2.TOKEN_ID, '') AS TOKEN_ID , A2.LOCK_CNT AS LOCK_CNT , COALESCE(DATE_FORMAT(A2.LOCK_LAST_PNTTM, '%Y-%m-%d %H:%i:%s'), '') AS LOCK_LAST_PNTTM , COALESCE(DATE_FORMAT(A2.CHG_PWD_LAST_PNTTM, '%Y-%m-%d %H:%i:%s'), '') AS CHG_PWD_LAST_PNTTM , COALESCE(A2.TERMS1_YN, 'N') AS TERMS1_YN , COALESCE(A2.TERMS2_YN, 'N') AS TERMS2_YN , COALESCE(A2.TERMS3_YN, 'N') AS TERMS3_YN , COALESCE(A2.TERMS4_YN, 'N') AS TERMS4_YN , COALESCE(A2.NOTICE_YN, 'N') AS NOTICE_YN , COALESCE(A2.EVENT_NOTI_YN, 'N') AS EVENT_NOTI_YN , COALESCE(A2.MAIL_NOTI_YN, 'N') AS MAIL_NOTI_YN , COALESCE(A2.SMS_NOTI_YN, 'N') AS SMS_NOTI_YN , COALESCE(A2.CERT_YN, 'N') AS CERT_YN , COALESCE(DATE_FORMAT(A2.CERT_DATE, '%Y-%m-%d %H:%i:%s'), '') AS CERT_DATE , COALESCE(A2.PROFILE, '') AS PROFILE , COALESCE(A2.PROFILE_GB, '') AS PROFILE_GB , COALESCE(A2.TEST_YN, 'N') AS TEST_YN , COALESCE(A2.SESSION_KEY, '') AS SESSION_KEY , COALESCE(DATE_FORMAT(A2.SESSION_LIMIT, '%Y-%m-%d %H:%i:%s'), '') AS SESSION_LIMIT , COALESCE(DATE_FORMAT(A2.APPROVE_DE, '%Y-%m-%d'), '') AS APPROVE_DE , COALESCE(A2.USER_PIC, '') AS USER_PIC , COALESCE(A2.CITIZEN_YN, 'N') AS CITIZEN_YN , COALESCE(A2.SINGLE_YN, 'N') AS SINGLE_YN , COALESCE(A2.MINOR_YN, 'N') AS MINOR_YN , COALESCE(A2.BASIC_YN, 'N') AS BASIC_YN , COALESCE(A2.POOR_YN, 'N') AS POOR_YN , CASE WHEN A2.BASIC_YN = 'Y' AND A2.POOR_YN = 'Y' THEN '기초생활수급자, 차상위계층' WHEN A2.BASIC_YN = 'Y' THEN '기초생활수급자' WHEN A2.POOR_YN = 'Y' THEN '차상위계층' ELSE '' END AS LOW_INCOME_NM , COALESCE(A2.FARM_YN, 'N') AS FARM_YN , COALESCE(A2.ATTA_FILE, '') AS ATTA_FILE , COALESCE(A2.SUBJECT_DESC, '') AS SUBJECT_DESC , COALESCE(A2.PROFILE_DESC, '') AS PROFILE_DESC , COALESCE(A2.BIZNO_FILE, '') AS BIZNO_FILE , COALESCE(A2.RELATION_GB, 'M') AS RELATION_GB , CASE A2.RELATION_GB WHEN 'F' THEN '부' WHEN 'M' THEN '모' WHEN 'E' THEN '기타' ELSE '' END AS RELATION_GB_NM , COALESCE(A2.FARM_DESC, '') AS FARM_DESC FROM ARMUSER A2 WHERE 1=1
AND A2.USER_SE = #{userSe}
AND DECRYPT(A2.USER_NM) LIKE CONCAT('%', #{searchKeyword}, '%')
AND A2.USER_ID LIKE CONCAT('%', #{searchKeyword}, '%')
AND DECRYPT(A2.MBTLNUM) LIKE CONCAT('%', #{searchKeyword}, '%')
AND A2.MBER_STTUS = #{mberSttus}
) A1

SELECT COUNT(1) FROM ARMUSER A2 WHERE 1=1
AND A2.USER_SE = #{userSe}
AND DECRYPT(A2.USER_NM) LIKE CONCAT('%', #{searchKeyword}, '%')
AND A2.USER_ID LIKE CONCAT('%', #{searchKeyword}, '%')
AND DECRYPT(A2.MBTLNUM) LIKE CONCAT('%', #{searchKeyword}, '%')
AND A2.MBER_STTUS = #{mberSttus}

SELECT * FROM ( SELECT ROW_NUMBER() OVER (ORDER BY A2.SBSCRB_DE DESC) AS RNUM , COALESCE(A2.ESNTL_ID, '') AS ESNTL_ID , COALESCE(DECRYPT(A2.USER_NM), '') AS USER_NM , COALESCE(A2.SCHOOL_NM, '') AS SCHOOL_NM , COALESCE(DECRYPT(A2.ADRES), '') AS ADRES , COALESCE(DECRYPT(A2.DETAIL_ADRES), '') AS DETAIL_ADRES , COALESCE(FN_MASK_PHONE(DECRYPT(A2.OFFM_TELNO), 'N'), '') AS OFFM_TELNO , COALESCE(FN_MASK_PHONE(DECRYPT(A2.MBTLNUM), 'N'), '') AS USR_TELNO , COALESCE( (SELECT GROUP_CONCAT(DISTINCT D.SUB_NM ORDER BY D.SUB_NM SEPARATOR ',') FROM ARTEDUM AM INNER JOIN ARTEDUD D ON D.EDU_ESNTL_ID = AM.EDU_ESNTL_ID AND D.EDU_GB = AM.EDU_GB AND D.STTUS_CODE = 'A' WHERE AM.EDU_ESNTL_ID = A2.ESNTL_ID AND AM.STTUS_CODE = 'A'), '' ) AS SUB_NM_LIST , COALESCE(A2.USER_PIC, '') AS USER_PIC , (SELECT MIN(F.SEQ) FROM ARTFILE F WHERE F.FILE_ID = A2.USER_PIC AND TRIM(COALESCE(A2.USER_PIC, '')) != '') AS USER_PIC_SEQ , COALESCE(A2.PROFILE_DESC, '') AS PROFILE_DESC FROM ARMUSER A2 WHERE 1=1 AND A2.USER_SE = 'ANR' AND A2.MBER_STTUS = 'P'
AND (DECRYPT(A2.USER_NM) LIKE CONCAT('%', #{searchKeyword}, '%') OR A2.SCHOOL_NM LIKE CONCAT('%', #{searchKeyword}, '%'))
) A1 LIMIT #{lengthPage} OFFSET #{startIndex}

SELECT 1 AS exist FROM armuser a2 WHERE 1=1
AND a2.CRTFC_DN_VALUE = #{_parameter}
LIMIT 1

SELECT 1 AS exist FROM armuser a2 WHERE 1=1
AND a2.USER_ID = #{_parameter}
LIMIT 1

mapper.update:
UPDATE ARMUSER
   SET USER_PIC = ''
 WHERE ESNTL_ID = #{_parameter}

UPDATE ARMUSER
   SET ATTA_FILE = ''
 WHERE ESNTL_ID = #{_parameter}

UPDATE ARMUSER
   SET BIZNO_FILE = ''
 WHERE ESNTL_ID = #{_parameter}
